1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const LOYALTY_DISCOUNT = -0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT = -0.15;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
35	type Customer = { yearsWithMHPCO?: number; firstInsurance?: boolean };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type QuoteStep = { op: "quote"; items: Item[] };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	type Step = QuoteStep | ClaimStep;
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	type Policy = { items: Item[]; cap: number };
44	
45	const lookupByType = (table: Record<string, number>, type: string): number => {
46	  const value = table[type];
47	  if (value === undefined) throw new Error(`unknown item type: ${type}`);
48	  return value;
49	};
50	
51	const basePremiumFor = (type: string): number => lookupByType(BASE_PREMIUM, type);
52	
53	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
54	
55	const isMainItem = (item: Item): boolean => !isComponent(item);
56	
57	const groupByType = (items: Item[]): Map<string, number> =>
58	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
59	
60	const componentGroupPremium = (type: string, count: number): number =>
61	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
62	
63	const componentsPremium = (items: Item[]): number =>
64	  Array.from(groupByType(items.filter(isComponent)))
65	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
66	
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
69	
70	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
71	
72	const itemRateAdjustment = (item: Item): number =>
73	  rateWhen(item.cursed === true, CURSED_SURCHARGE) +
74	  rateWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
75	
76	const itemPremium = (item: Item): number =>
77	  basePremiumFor(item.type) * (1 + itemRateAdjustment(item));
78	
79	type PremiumBreakdown = { base: number; withSurcharges: number };
80	
81	const addBreakdowns = (a: PremiumBreakdown, b: PremiumBreakdown): PremiumBreakdown => ({
82	  base: a.base + b.base,
83	  withSurcharges: a.withSurcharges + b.withSurcharges,
84	});
85	
86	const mainItemBreakdown = (item: Item): PremiumBreakdown => ({
87	  base: basePremiumFor(item.type),
88	  withSurcharges: itemPremium(item),
89	});
90	
91	const componentsBreakdown = (items: Item[]): PremiumBreakdown => {
92	  const total = componentsPremium(items);
93	  return { base: total, withSurcharges: total };
94	};
95	
96	const itemsBreakdown = (items: Item[]): PremiumBreakdown =>
97	  items
98	    .filter(isMainItem)
99	    .map(mainItemBreakdown)
100	    .reduce(addBreakdowns, componentsBreakdown(items));
101	
102	const isLongStanding = (customer: Customer): boolean =>
103	  (customer.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
104	
105	const policyRateAdjustment = (customer: Customer, isFollowUp: boolean): number =>
106	  rateWhen(customer.firstInsurance === true, FIRST_INSURANCE_SURCHARGE) +
107	  rateWhen(isLongStanding(customer), LOYALTY_DISCOUNT) +
108	  rateWhen(isFollowUp, FOLLOW_UP_DISCOUNT);
109	
110	const FLOATING_POINT_EPSILON = 1e-9;
111	
112	const roundUpInOurFavor = (amount: number): number =>
113	  Math.ceil(amount - FLOATING_POINT_EPSILON);
114	
115	const policyPremium = (customer: Customer, items: Item[], isFollowUp: boolean): number => {
116	  const { base, withSurcharges } = itemsBreakdown(items);
117	  return withSurcharges + base * policyRateAdjustment(customer, isFollowUp) + PROCESSING_FEE;
118	};
119	
120	const isFollowUpStep = (stepIndex: number): boolean => stepIndex > 0;
121	
122	const quoteResult = (customer: Customer, items: Item[], stepIndex: number): { premium: number } => ({
123	  premium: roundUpInOurFavor(policyPremium(customer, items, isFollowUpStep(stepIndex))),
124	});
125	
126	const insuranceValueFor = (type: string): number => lookupByType(INSURANCE_VALUE, type);
127	
128	const policyInsuranceSum = (items: Item[]): number =>
129	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
130	
131	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
132	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
133	
134	const qualifiesForHighEnchantmentRule = (item: Item | undefined): boolean =>
135	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
136	
137	const reimbursementRate = (item: Item | undefined): number =>
138	  qualifiesForHighEnchantmentRule(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
139	
140	const findInsuredItem = (items: Item[], type: string): Item | undefined =>
141	  items.find((i) => i.type === type);
142	
143	const damagePayout = (damage: Damage, items: Item[]): number => {
144	  const item = findInsuredItem(items, damage.itemType);
145	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
146	};
147	
148	const totalRawPayout = (damages: Damage[], items: Item[]): number =>
149	  damages.reduce((sum, d) => sum + damagePayout(d, items), 0);
150	
151	const openPolicy = (items: Item[]): Policy => ({
152	  items,
153	  cap: policyInsuranceSum(items) * CAP_MULTIPLIER,
154	});
155	
156	const settleClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
157	  const payout = Math.min(totalRawPayout(incident.damages, policy.items), policy.cap);
158	  policy.cap -= payout;
159	  return { payout, remainingCap: policy.cap };
160	};
161	
162	type QuoteResult = { premium: number };
163	type ClaimResult = { payout: number; remainingCap: number };
164	type StepResult = QuoteResult | ClaimResult;
165	
166	const processStep = (customer: Customer, policies: Policy[]) =>
167	  (step: Step, stepIndex: number): StepResult => {
168	    if (step.op === "quote") {
169	      policies[stepIndex] = openPolicy(step.items);
170	      return quoteResult(customer, step.items, stepIndex);
171	    }
172	    return settleClaim(policies[step.policy], step.incident);
173	  };
174	
175	export const runScenario = (input: unknown): { results: StepResult[] } => {
176	  const { customer, steps } = input as Scenario;
177	  const policies: Policy[] = [];
178	  return { results: steps.map(processStep(customer, policies)) };
179	};
